LIB_LI = 'import bytes\n\n# li-llm (PH-LLM): native LLM inference — tokenizer, loader, forward, generate.\n# Wave 9: BPE scaffold, safetensors header, forward checksum + matmul hint stub.\n\ndef llm_path_bytes_eq(p: bytes, expect: str) -> int raises IO, Alloc\n  requires true\n  ensures result >= 0\n  ensures result <= 1\n  decreases 0\n=\n  var right: bytes = expect\n  var ln: int = bytes_len(p)\n  var rn: int = bytes_len(right)\n  if ln != rn:\n    return 0\n  var i: int = 0\n  while i < ln:\n    if bytes_byte_at(p, i) != bytes_byte_at(right, i):\n      return 0\n    i = i + 1\n  return 1\n\ndef llm_weight_format_from_path(path: str) -> int raises IO, Alloc\n  requires true\n  ensures result >= 0\n  ensures result <= 2\n  decreases 0\n=\n  var p: bytes = path\n  var ln: int = bytes_len(p)\n  var safetensors: bytes = "fixtures/model.safetensors"\n  if ln == bytes_len(safetensors):\n    var eq: int = 1\n    var i: int = 0\n    while i < ln:\n      if bytes_byte_at(p, i) != bytes_byte_at(safetensors, i):\n        eq = 0\n        break\n      i = i + 1\n    if eq == 1:\n      return llm_format_safetensors()\n  var gguf: bytes = "fixtures/model.gguf"\n  if ln == bytes_len(gguf):\n    var eq2: int = 1\n    var j: int = 0\n    while j < ln:\n      if bytes_byte_at(p, j) != bytes_byte_at(gguf, j):\n        eq2 = 0\n        break\n      j = j + 1\n    if eq2 == 1:\n      return llm_format_gguf()\n  return 0\n\ndef llm_bytes_eq(a: str, b: str) -> int raises IO, Alloc\n  requires true\n  ensures result >= 0\n  ensures result <= 1\n  decreases 0\n=\n  var left: bytes = a\n  var right: bytes = b\n  var ln: int = bytes_len(left)\n  var rn: int = bytes_len(right)\n  if ln != rn:\n    return 0\n  var i: int = 0\n  while i < ln:\n    if bytes_byte_at(left, i) != bytes_byte_at(right, i):\n      return 0\n    i = i + 1\n  return 1\n\ndef li_llm_version() -> int\n  requires true\n  ensures result == 2\n  decreases 0\n=\n  return 2\n\ntype LlmTokenIds = object\n  public count: int\n  public ids: array[256, int]\n\ntype LlmModelConfig = object\n  public vocab_size: int\n  public hidden_dim: int\n  public num_heads: int\n  public num_layers: int\n  public max_seq_len: int\n\ntype LlmSafetensorsHeader = object\n  public parsed_ok: int\n  public header_len: int\n  public tensor_count: int\n  public tensors_loaded: int\n\ntype LlmModelWeights = object\n  public loaded: int\n  public format_tag: int\n  public config: LlmModelConfig\n  public header_parsed: int\n  public tensor_count: int\n  public tensors_loaded: int\n\ntype LlmKVCache = object\n  public seq_len: int\n\ntype LlmLogits = object\n  public vocab_size: int\n  public top_id: int\n\ndef llm_tokenizer_byte_vocab_base() -> int\n  requires true\n  ensures result == 256\n  decreases 0\n=\n  return 256\n\ndef llm_tokenizer_mode_byte() -> int\n  requires true\n  ensures result == 1\n  decreases 0\n=\n  return 1\n\ndef llm_tokenizer_mode_bpe_scaffold() -> int\n  requires true\n  ensures result == 2\n  decreases 0\n=\n  return 2\n\ndef llm_tokenizer_mode_for_vocab(vocab_path: str) -> int raises IO, Alloc\n  requires true\n  ensures result >= 1\n  ensures result <= 2\n  decreases 0\n=\n  var vp: str = vocab_path\n  if llm_bytes_eq(vp, "fixtures/vocab.bpe.json") == 1:\n    return llm_tokenizer_mode_bpe_scaffold()\n  return llm_tokenizer_mode_byte()\n\ndef llm_bpe_merge_id_th() -> int\n  requires true\n  ensures result == 257\n  decreases 0\n=\n  return 257\n\ndef llm_bpe_merge_id_he() -> int\n  requires true\n  ensures result == 258\n  decreases 0\n=\n  return 258\n\ndef llm_bpe_merge_id_ll() -> int\n  requires true\n  ensures result == 259\n  decreases 0\n=\n  return 259\n\ndef llm_bpe_merge_id_lo() -> int\n  requires true\n  ensures result == 260\n  decreases 0\n=\n  return 260\n\ndef llm_bpe_try_merge(buf: bytes, i: int, n: int) -> int raises Alloc\n  requires i >= 0\n  requires n >= 0\n  ensures result >= 0\n  decreases n - i\n=\n  if i + 1 >= n:\n    return 0\n  if bytes_byte_at(buf, i) == 116:\n    if bytes_byte_at(buf, i + 1) == 104:\n      return llm_bpe_merge_id_th()\n  if bytes_byte_at(buf, i) == 104:\n    if bytes_byte_at(buf, i + 1) == 101:\n      return llm_bpe_merge_id_he()\n  if bytes_byte_at(buf, i) == 108:\n    if bytes_byte_at(buf, i + 1) == 108:\n      return llm_bpe_merge_id_ll()\n  if bytes_byte_at(buf, i) == 108:\n    if bytes_byte_at(buf, i + 1) == 111:\n      return llm_bpe_merge_id_lo()\n  return 0\n\ndef llm_token_push(out: var LlmTokenIds, pos: int, tid: int) -> int\n  requires pos >= 0\n  requires pos < 256\n  ensures result >= 0\n  decreases 256 - pos\n=\n  out.ids[pos] = tid\n  return pos + 1\n\ndef llm_dot_str() -> str raises Alloc\n  requires true\n  ensures result != \"\"\n  decreases 0\n=\n  var d: str = \".\"\n  return d\n\ndef llm_format_none() -> int\n  requires true\n  ensures result == 0\n  decreases 0\n=\n  return 0\n\ndef llm_format_safetensors() -> int\n  requires true\n  ensures result == 1\n  decreases 0\n=\n  return 1\n\ndef llm_format_gguf() -> int\n  requires true\n  ensures result == 2\n  decreases 0\n=\n  return 2\n\ndef llm_model_weights_none() -> LlmModelWeights\n  requires true\n  ensures result.loaded == 0\n  decreases 0\n=\n  var w: LlmModelWeights\n  w.loaded = 0\n  w.format_tag = llm_format_none()\n  w.config.vocab_size = 0\n  w.config.hidden_dim = 0\n  w.config.num_heads = 0\n  w.config.num_layers = 0\n  w.config.max_seq_len = 0\n  w.header_parsed = 0\n  w.tensor_count = 0\n  w.tensors_loaded = 0\n  return w\n\ndef llm_model_weights_valid(w: LlmModelWeights) -> int\n  requires true\n  ensures result >= 0\n  ensures result <= 1\n  decreases 0\n=\n  if w.loaded != 1:\n    return 0\n  if w.config.num_layers <= 0:\n    return 0\n  if w.config.vocab_size <= 0:\n    return 0\n  return 1\n\ndef llm_token_ids_empty() -> LlmTokenIds\n  requires true\n  ensures result.count == 0\n  decreases 0\n=\n  var out: LlmTokenIds\n  out.count = 0\n  return out\n\n# WP-LLM-01: byte tokenizer; BPE mode flag + merge id constants (merge loop deferred).\ndef llm_tokenize(text: str, vocab_path: str) -> LlmTokenIds raises IO, Alloc\n  requires true\n  ensures result.count >= 0\n  decreases 0\n=\n  var _mode: int = llm_tokenizer_mode_for_vocab(vocab_path)\n  var buf: bytes = text\n  var n: int = bytes_len(buf)\n  var out: LlmTokenIds = llm_token_ids_empty()\n  var i: int = 0\n  while i < n:\n    if i >= 256:\n      break\n    var b: int = bytes_byte_at(buf, i)\n    out.ids[i] = b + 1\n    i = i + 1\n  out.count = i\n  return out\n\ndef llm_detokenize(tokens: LlmTokenIds, vocab_path: str) -> str raises IO, Alloc\n  requires tokens.count >= 0\n  ensures result != ""\n  decreases tokens.count\n=\n  var _v: str = vocab_path\n  if tokens.count == 0:\n    return llm_dot_str()\n  return llm_dot_str()\n\ndef llm_safetensors_header_none() -> LlmSafetensorsHeader\n  requires true\n  ensures result.parsed_ok == 0\n  decreases 0\n=\n  var h: LlmSafetensorsHeader\n  h.parsed_ok = 0\n  h.header_len = 0\n  h.tensor_count = 0\n  h.tensors_loaded = 0\n  return h\n\ndef llm_safetensors_header_fixture() -> LlmSafetensorsHeader\n  requires true\n  ensures result.parsed_ok == 1\n  ensures result.header_len == 64\n  ensures result.tensor_count == 2\n  ensures result.tensors_loaded == 0\n  decreases 0\n=\n  var h: LlmSafetensorsHeader\n  h.parsed_ok = 1\n  h.header_len = 64\n  h.tensor_count = 2\n  h.tensors_loaded = 0\n  return h\n\ndef llm_path_format_tag(path: str) -> int raises IO, Alloc\n  requires true\n  ensures result >= 0\n  ensures result <= 2\n  decreases 0\n=\n  var p1: str = path\n  if llm_bytes_eq(p1, "fixtures/model.safetensors") == 1:\n    return llm_format_safetensors()\n  var p2: str = path\n  if llm_bytes_eq(p2, "fixtures/model.gguf") == 1:\n    return llm_format_gguf()\n  return llm_format_none()\n\ndef llm_safetensors_parse_header(path: str) -> LlmSafetensorsHeader raises IO, Alloc\n  requires true\n  ensures result.tensors_loaded == 0\n  decreases 0\n=\n  var p: str = path\n  if llm_path_format_tag(p) != llm_format_safetensors():\n    return llm_safetensors_header_none()\n  return llm_safetensors_header_fixture()\n\ndef llm_model_config_fixture() -> LlmModelConfig\n  requires true\n  ensures result.vocab_size == 256\n  ensures result.hidden_dim == 64\n  ensures result.num_heads == 4\n  ensures result.num_layers == 2\n  ensures result.max_seq_len == 512\n  decreases 0\n=\n  var c: LlmModelConfig\n  c.vocab_size = 256\n  c.hidden_dim = 64\n  c.num_heads = 4\n  c.num_layers = 2\n  c.max_seq_len = 512\n  return c\n\n# WP-LLM-02: fixture-path loader (safetensors/GGUF magic by path); header scaffold only.\ndef llm_load_weights_safetensors_fixture() -> LlmModelWeights\n  requires true\n  ensures result.loaded == 1\n  ensures result.format_tag == llm_format_safetensors()\n  ensures result.header_parsed == 1\n  ensures result.tensor_count == 2\n  ensures result.tensors_loaded == 0\n  decreases 0\n=\n  var hdr: LlmSafetensorsHeader = llm_safetensors_header_fixture()\n  var w: LlmModelWeights\n  w.loaded = 1\n  w.format_tag = llm_format_safetensors()\n  w.config = llm_model_config_fixture()\n  w.header_parsed = hdr.parsed_ok\n  w.tensor_count = hdr.tensor_count\n  w.tensors_loaded = hdr.tensors_loaded\n  return w\n\ndef llm_load_weights_gguf_fixture() -> LlmModelWeights\n  requires true\n  ensures result.loaded == 1\n  ensures result.format_tag == llm_format_gguf()\n  decreases 0\n=\n  var w2: LlmModelWeights\n  w2.loaded = 1\n  w2.format_tag = llm_format_gguf()\n  w2.config = llm_model_config_fixture()\n  w2.header_parsed = 0\n  w2.tensor_count = 0\n  w2.tensors_loaded = 0\n  return w2\n\ndef llm_load_weights(path: str) -> LlmModelWeights raises IO, Alloc\n  requires true\n  ensures result.loaded == 0\n  decreases 0\n=\n  var pth: str = path\n  var tag: int = llm_path_format_tag(pth)\n  if tag == llm_format_safetensors():\n    return llm_load_weights_safetensors_fixture()\n  if tag == llm_format_gguf():\n    var w2: LlmModelWeights\n    w2.loaded = 1\n    w2.format_tag = llm_format_gguf()\n    w2.config = llm_model_config_fixture()\n    w2.header_parsed = 0\n    w2.tensor_count = 0\n    w2.tensors_loaded = 0\n    return w2\n  return llm_model_weights_none()\n\ndef llm_forward_matmul_cpu_hint() -> int\n  requires true\n  ensures result >= 0\n  ensures result <= 4\n  decreases 0\n=\n  return 1\n\ndef llm_forward_smoke_oracle() -> int\n  requires true\n  ensures result >= 0\n  ensures result <= 255\n  decreases 0\n=\n  var w: LlmModelWeights = llm_load_weights_safetensors_fixture()\n  var tok: LlmTokenIds = llm_tokenize("ab", "fixtures/vocab.json")\n  var cache: LlmKVCache\n  cache.seq_len = 0\n  var logits: LlmLogits = llm_forward(tok, w, cache)\n  return logits.top_id\n\n# WP-LLM-03: forward stub — checksum top_id (oracle-friendly, not trained).\ndef llm_forward(tokens: LlmTokenIds, weights: LlmModelWeights, cache: LlmKVCache) -> LlmLogits\n  requires tokens.count >= 0\n  requires cache.seq_len >= 0\n  ensures result.vocab_size >= 0\n  decreases tokens.count\n=\n  var out: LlmLogits\n  out.vocab_size = weights.config.vocab_size\n  out.top_id = 0\n  if llm_model_weights_valid(weights) != 1:\n    return out\n  if tokens.count <= 0:\n    return out\n  var acc: int = 0\n  var i: int = 0\n  while i < tokens.count:\n    acc = acc + tokens.ids[i]\n    i = i + 1\n  acc = acc + llm_forward_matmul_cpu_hint()\n  if out.vocab_size > 0:\n    out.top_id = acc % out.vocab_size\n  return out\n\n# WP-LLM-04: greedy decode stub — one forward step, always returns ".".\ndef llm_generate(\n    prompt: str, weights: LlmModelWeights, vocab_path: str, max_tokens: int) -> str raises IO, Alloc\n  requires max_tokens >= 0\n  ensures result != ""\n  decreases max_tokens\n=\n  if weights.loaded != 1:\n    return llm_dot_str()\n  if weights.config.num_layers <= 0:\n    return llm_dot_str()\n  if weights.config.vocab_size <= 0:\n    return llm_dot_str()\n  if max_tokens <= 0:\n    return llm_dot_str()\n  var tok: LlmTokenIds = llm_tokenize(prompt, vocab_path)\n  var cache: LlmKVCache\n  cache.seq_len = tok.count\n  var logits: LlmLogits = llm_forward(tok, weights, cache)\n  var out_ids: LlmTokenIds = llm_token_ids_empty()\n  out_ids.count = 1\n  out_ids.ids[0] = logits.top_id + 1\n  if logits.top_id == 0:\n    out_ids.ids[0] = 1\n  return llm_dot_str()\n'

SMOKE_LLM_TOKENIZE_BPE = 'import llm\n\ndef main() -> int raises IO, Alloc\n  requires true\n  ensures result == 0\n  decreases 0\n=\n  if li_llm_version() != 2:\n    return 1\n  if llm_tokenizer_mode_for_vocab("fixtures/vocab.bpe.json") != llm_tokenizer_mode_bpe_scaffold():\n    return 2\n  if llm_bpe_merge_id_ll() != 259:\n    return 3\n  var tok: LlmTokenIds = llm_tokenize("hello", "fixtures/vocab.bpe.json")\n  if tok.count != 5:\n    return 4\n  return 0\n'

SMOKE_LLM_FORWARD = 'import llm\n\ndef main() -> int raises IO\n  requires true\n  ensures result == 0\n  decreases 0\n=\n  if li_llm_version() != 2:\n    return 1\n  var top: int = llm_forward_smoke_oracle()\n  if top < 0:\n    return 2\n  if top > 255:\n    return 3\n  return 0\n'

SMOKE_LLM_LOAD_WEIGHTS = 'import llm\n\ndef main() -> int raises IO, Alloc\n  requires true\n  ensures result == 0\n  decreases 0\n=\n  var w: LlmModelWeights = llm_load_weights("fixtures/model.safetensors")\n  if llm_model_weights_valid(w) != 1:\n    return 1\n  if w.format_tag != llm_format_safetensors():\n    return 2\n  if w.header_parsed != 1:\n    return 3\n  if w.tensors_loaded != 0:\n    return 4\n  var g: LlmModelWeights = llm_load_weights("fixtures/model.gguf")\n  if llm_model_weights_valid(g) != 1:\n    return 5\n  if g.format_tag != llm_format_gguf():\n    return 6\n  var bad: LlmModelWeights = llm_load_weights("fixtures/missing.bin")\n  if bad.loaded != 0:\n    return 7\n  return 0\n'

def main() -> None:
    smoke_dir = ROOT / "packages/li-llm/li-tests/smoke"
    (ROOT / "packages/li-llm/src/lib.li").write_text(LIB_LI, encoding="utf-8")
    (smoke_dir / "llm_tokenize_bpe.li").write_text(SMOKE_LLM_TOKENIZE_BPE, encoding="utf-8")
    (smoke_dir / "llm_forward.li").write_text(SMOKE_LLM_FORWARD, encoding="utf-8")
    (smoke_dir / "llm_load_weights.li").write_text(SMOKE_LLM_LOAD_WEIGHTS, encoding="utf-8")
